import{_ as i,o as l,c as a,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"TUI","description":"","frontmatter":{"read_when":["你想要 TUI 的新手友好演练","你需要 TUI 功能、命令和快捷键的完整列表"],"summary":"终端 UI（TUI）：从任何机器连接到 Gateway 网关","title":"TUI","x-i18n":{"generated_at":"2026-02-03T10:13:10Z","model":"claude-opus-4-5","provider":"pi","source_hash":"4bf5b0037bbb3a166289f2f0a9399489637d4cf26335ae3577af9ea83eee747e","source_path":"web/tui.md","workflow":15}},"headers":[],"relativePath":"zh-CN/web/tui.md","filePath":"zh-CN/web/tui.md","lastUpdated":1771906665000}'),t={name:"zh-CN/web/tui.md"};function d(o,e,n,c,h,r){return l(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="tui-终端-ui" tabindex="-1"><a class="header-anchor" href="#tui-终端-ui">#</a> TUI（终端 UI）</h1><h2 id="快速开始" tabindex="-1"><a class="header-anchor" href="#快速开始">#</a> 快速开始</h2><ol><li>启动 Gateway 网关。</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="2"><li>打开 TUI。</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="3"><li>输入消息并按 Enter。</li></ol><p>远程 Gateway 网关：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ws://</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">hos</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --token</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gateway-toke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你的 Gateway 网关使用密码认证，请使用 <code>--password</code>。</p><h2 id="你看到的内容" tabindex="-1"><a class="header-anchor" href="#你看到的内容">#</a> 你看到的内容</h2><ul><li>标题栏：连接 URL、当前智能体、当前会话。</li><li>聊天日志：用户消息、助手回复、系统通知、工具卡片。</li><li>状态行：连接/运行状态（连接中、运行中、流式传输中、空闲、错误）。</li><li>页脚：连接状态 + 智能体 + 会话 + 模型 + think/verbose/reasoning + token 计数 + 投递状态。</li><li>输入：带自动完成的文本编辑器。</li></ul><h2 id="心智模型-智能体-会话" tabindex="-1"><a class="header-anchor" href="#心智模型-智能体-会话">#</a> 心智模型：智能体 + 会话</h2><ul><li>智能体是唯一的标识符（例如 <code>main</code>、<code>research</code>）。Gateway 网关公开列表。</li><li>会话属于当前智能体。</li><li>会话键存储为 <code>agent:&lt;agentId&gt;:&lt;sessionKey&gt;</code>。 <ul><li>如果你输入 <code>/session main</code>，TUI 会将其扩展为 <code>agent:&lt;currentAgent&gt;:main</code>。</li><li>如果你输入 <code>/session agent:other:main</code>，你会显式切换到该智能体会话。</li></ul></li><li>会话范围： <ul><li><code>per-sender</code>（默认）：每个智能体有多个会话。</li><li><code>global</code>：TUI 始终使用 <code>global</code> 会话（选择器可能为空）。</li></ul></li><li>当前智能体 + 会话始终在页脚中可见。</li></ul><h2 id="发送-投递" tabindex="-1"><a class="header-anchor" href="#发送-投递">#</a> 发送 + 投递</h2><ul><li>消息发送到 Gateway 网关；默认情况下不投递到提供商。</li><li>开启投递： <ul><li><code>/deliver on</code></li><li>或设置面板</li><li>或使用 <code>opensoul tui --deliver</code> 启动</li></ul></li></ul><h2 id="选择器-覆盖层" tabindex="-1"><a class="header-anchor" href="#选择器-覆盖层">#</a> 选择器 + 覆盖层</h2><ul><li>模型选择器：列出可用模型并设置会话覆盖。</li><li>智能体选择器：选择不同的智能体。</li><li>会话选择器：仅显示当前智能体的会话。</li><li>设置：切换投递、工具输出展开和思考可见性。</li></ul><h2 id="键盘快捷键" tabindex="-1"><a class="header-anchor" href="#键盘快捷键">#</a> 键盘快捷键</h2><ul><li>Enter：发送消息</li><li>Esc：中止活动运行</li><li>Ctrl+C：清除输入（按两次退出）</li><li>Ctrl+D：退出</li><li>Ctrl+L：模型选择器</li><li>Ctrl+G：智能体选择器</li><li>Ctrl+P：会话选择器</li><li>Ctrl+O：切换工具输出展开</li><li>Ctrl+T：切换思考可见性（重新加载历史）</li></ul><h2 id="斜杠命令" tabindex="-1"><a class="header-anchor" href="#斜杠命令">#</a> 斜杠命令</h2><p>核心：</p><ul><li><code>/help</code></li><li><code>/status</code></li><li><code>/agent &lt;id&gt;</code>（或 <code>/agents</code>）</li><li><code>/session &lt;key&gt;</code>（或 <code>/sessions</code>）</li><li><code>/model &lt;provider/model&gt;</code>（或 <code>/models</code>）</li></ul><p>会话控制：</p><ul><li><code>/think &lt;off|minimal|low|medium|high&gt;</code></li><li><code>/verbose &lt;on|full|off&gt;</code></li><li><code>/reasoning &lt;on|off|stream&gt;</code></li><li><code>/usage &lt;off|tokens|full&gt;</code></li><li><code>/elevated &lt;on|off|ask|full&gt;</code>（别名：<code>/elev</code>）</li><li><code>/activation &lt;mention|always&gt;</code></li><li><code>/deliver &lt;on|off&gt;</code></li></ul><p>会话生命周期：</p><ul><li><code>/new</code> 或 <code>/reset</code>（重置会话）</li><li><code>/abort</code>（中止活动运行）</li><li><code>/settings</code></li><li><code>/exit</code></li></ul><p>其他 Gateway 网关斜杠命令（例如 <code>/context</code>）会转发到 Gateway 网关并显示为系统输出。参见<a href="/docs/tools/slash-commands">斜杠命令</a>。</p><h2 id="本地-shell-命令" tabindex="-1"><a class="header-anchor" href="#本地-shell-命令">#</a> 本地 shell 命令</h2><ul><li>以 <code>!</code> 为前缀的行会在 TUI 主机上运行本地 shell 命令。</li><li>TUI 每个会话会提示一次以允许本地执行；拒绝会在该会话中禁用 <code>!</code>。</li><li>命令在 TUI 工作目录中以全新的非交互式 shell 运行（无持久化 <code>cd</code>/环境变量）。</li><li>单独的 <code>!</code> 会作为普通消息发送；前导空格不会触发本地执行。</li></ul><h2 id="工具输出" tabindex="-1"><a class="header-anchor" href="#工具输出">#</a> 工具输出</h2><ul><li>工具调用显示为带有参数 + 结果的卡片。</li><li>Ctrl+O 在折叠/展开视图之间切换。</li><li>工具运行时，部分更新会流式传输到同一张卡片。</li></ul><h2 id="历史-流式传输" tabindex="-1"><a class="header-anchor" href="#历史-流式传输">#</a> 历史 + 流式传输</h2><ul><li>连接时，TUI 加载最新历史（默认 200 条消息）。</li><li>流式响应原地更新直到完成。</li><li>TUI 还监听智能体工具事件以获得更丰富的工具卡片。</li></ul><h2 id="连接详情" tabindex="-1"><a class="header-anchor" href="#连接详情">#</a> 连接详情</h2><ul><li>TUI 以 <code>mode: &quot;tui&quot;</code> 向 Gateway 网关注册。</li><li>重新连接会显示系统消息；事件间隙会在日志中显示。</li></ul><h2 id="选项" tabindex="-1"><a class="header-anchor" href="#选项">#</a> 选项</h2><ul><li><code>--url &lt;url&gt;</code>：Gateway 网关 WebSocket URL（默认为配置或 <code>ws://127.0.0.1:&lt;port&gt;</code>）</li><li><code>--token &lt;token&gt;</code>：Gateway 网关令牌（如果需要）</li><li><code>--password &lt;password&gt;</code>：Gateway 网关密码（如果需要）</li><li><code>--session &lt;key&gt;</code>：会话键（默认：<code>main</code>，或范围为全局时为 <code>global</code>）</li><li><code>--deliver</code>：将助手回复投递到提供商（默认关闭）</li><li><code>--thinking &lt;level&gt;</code>：覆盖发送的思考级别</li><li><code>--timeout-ms &lt;ms&gt;</code>：智能体超时（毫秒）（默认为 <code>agents.defaults.timeoutSeconds</code>）</li></ul><h2 id="故障排除" tabindex="-1"><a class="header-anchor" href="#故障排除">#</a> 故障排除</h2><p>发送消息后没有输出：</p><ul><li>在 TUI 中运行 <code>/status</code> 以确认 Gateway 网关已连接且处于空闲/忙碌状态。</li><li>检查 Gateway 网关日志：<code>opensoul logs --follow</code>。</li><li>确认智能体可以运行：<code>opensoul status</code> 和 <code>opensoul models status</code>。</li><li>如果你期望消息出现在聊天渠道中，请启用投递（<code>/deliver on</code> 或 <code>--deliver</code>）。</li><li><code>--history-limit &lt;n&gt;</code>：要加载的历史条目数（默认 200）</li></ul><h2 id="故障排除-1" tabindex="-1"><a class="header-anchor" href="#故障排除-1">#</a> 故障排除</h2><ul><li><code>disconnected</code>：确保 Gateway 网关正在运行且你的 <code>--url/--token/--password</code> 正确。</li><li>选择器中没有智能体：检查 <code>opensoul agents list</code> 和你的路由配置。</li><li>会话选择器为空：你可能处于全局范围或还没有会话。</li></ul>',43)])])}const k=i(t,[["render",d]]);export{u as __pageData,k as default};
